    'Kairouan': { chef_lieu: 'Kairouan', population: '590 000', description: "Quatrième ville sainte de l'islam, capitale spirituelle du Maghreb, fondée en 670.", villes: ['Kairouan', 'Sbikha', 'Haffouz', 'El Alaa'], sites: ['Grande Mosquée de Kairouan (UNESCO, 670)', 'Médina de Kairouan (UNESCO)', 'Bassins des Aghlabides (IXe s.)'], gastronomie: ['Makroudh de Kairouan (gâteau dattes)', 'Lablabi', 'Couscous kairouanais', 'Mhalbiya (crème)'], histoire: "Kairouan fondée par Oqba ibn Nafi (670), première capitale du Maghreb islamique. Les Aghlabides en font leur capitale (IXe s.). Quatrième ville sainte de l'islam.", personnages: ['Oqba ibn Nafi (fondateur 670)', 'Ibn Rashiq al-Qayrawani (poète, Kairouan XIe s.)'] },
